SELECT * FROM(SELECT DISTINCT SGNP_NBR,SGNP_TYPE_DESC,SGNP_STYPE_DESC,SGNP_STYPE_AGR_NM,ELG_QSTN_TXT,SGNP_ID,ELG_INIT_RQR_RESP_TXT,ELG_FLWUP_RQR_RESP_TXT,ELG_CRIT_TYPE_CD,DPLY_SEQ_NBR,DATA_STAT_CD,CRE_DT,LAST_CHG_DT,LAST_CHG_USER_NM,EWT76_SGNP_ELG_CRIT_ID,-- op,ROW_NUMBER() over ( partition by ELG_QSTN_TXT,SGNP_IDorder by TBL_PRIORITY ASC, LAST_CHG_DT DESC ) AS row_num_partFROM(SELECT ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt76_sgnp_elg_crit.ELG_QSTN_TXT ELG_QSTN_TXT,ewt76_sgnp_elg_crit.SGNP_ID SGNP_ID,ewt76_sgnp_elg_crit.ELG_RQR_RESP_TXT ELG_INIT_RQR_RESP_TXT,ewt76_sgnp_elg_crit.ELG_FLWUP_RQR_RESP ELG_FLWUP_RQR_RESP_TXT,ewt76_sgnp_elg_crit.ELG_CRIT_TYPE_CD ELG_CRIT_TYPE_CD,ewt76_sgnp_elg_crit.DPLY_SEQ_NBR DPLY_SEQ_NBR,ewt76_sgnp_elg_crit.DATA_STAT_CD DATA_STAT_CD,ewt76_sgnp_elg_crit.CRE_DT CRE_DT,ewt76_sgnp_elg_crit.LAST_CHG_DT LAST_CHG_DT,ewt76_sgnp_elg_crit.LAST_CHG_USER_NM LAST_CHG_USER_NM,ewt76_sgnp_elg_crit.EWT76_SGNP_ELG_CRIT_ID,1 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT76_SGNP_ELG_CRIT LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT76_SGNP_ELG_CRIT.SGNP_ID = EWT14SGNP.SGNP_ID)--WHERE __CDC_OPERATION <> 'D'

UNIONSELECT ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt76_sgnp_elg_crit.ELG_QSTN_TXT ELG_QSTN_TXT,ewt76_sgnp_elg_crit.SGNP_ID SGNP_ID,ewt76_sgnp_elg_crit.ELG_RQR_RESP_TXT ELG_INIT_RQR_RESP_TXT,ewt76_sgnp_elg_crit.ELG_FLWUP_RQR_RESP ELG_FLWUP_RQR_RESP_TXT,ewt76_sgnp_elg_crit.ELG_CRIT_TYPE_CD ELG_CRIT_TYPE_CD,ewt76_sgnp_elg_crit.DPLY_SEQ_NBR DPLY_SEQ_NBR,ewt76_sgnp_elg_crit.DATA_STAT_CD DATA_STAT_CD,ewt76_sgnp_elg_crit.CRE_DT CRE_DT,ewt76_sgnp_elg_crit.LAST_CHG_DT LAST_CHG_DT,ewt76_sgnp_elg_crit.LAST_CHG_USER_NM LAST_CHG_USER_NM,ewt76_sgnp_elg_crit.EWT76_SGNP_ELG_CRIT_ID,-- op,2 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT14SGNP JOIN "fsa-prod-cnsv".EWT76_SGNP_ELG_CRIT ON (EWT14SGNP.SGNP_ID = EWT76_SGNP_ELG_CRIT.SGNP_ID)--WHERE __CDC_OPERATION <> 'D') STG_ALL) STG_UNQWHERE row_num_part = 1AND (
 (COALESCE(CAST(CRE_DT AS DATE), DATE '1900-01-01') <= CAST('2025-07-01' AS DATE))
    AND
    (COALESCE(CAST(LAST_CHG_DT AS DATE), DATE '1900-01-01') <= CAST('2025-07-01' AS DATE))
)
UNIONSELECT DISTINCTNULL SGNP_NBR,NULL SGNP_TYPE_DESC,NULL SGNP_STYPE_DESC,NULL SGNP_STYPE_AGR_NM,ewt76_sgnp_elg_crit.ELG_QSTN_TXT ELG_QSTN_TXT,ewt76_sgnp_elg_crit.SGNP_ID SGNP_ID,ewt76_sgnp_elg_crit.ELG_RQR_RESP_TXT ELG_INIT_RQR_RESP_TXT,ewt76_sgnp_elg_crit.ELG_FLWUP_RQR_RESP ELG_FLWUP_RQR_RESP_TXT,ewt76_sgnp_elg_crit.ELG_CRIT_TYPE_CD ELG_CRIT_TYPE_CD,ewt76_sgnp_elg_crit.DPLY_SEQ_NBR DPLY_SEQ_NBR,ewt76_sgnp_elg_crit.DATA_STAT_CD DATA_STAT_CD,ewt76_sgnp_elg_crit.CRE_DT CRE_DT,ewt76_sgnp_elg_crit.LAST_CHG_DT LAST_CHG_DT,ewt76_sgnp_elg_crit.LAST_CHG_USER_NM LAST_CHG_USER_NM,ewt76_sgnp_elg_crit.EWT76_SGNP_ELG_CRIT_ID,-- op,1 AS row_num_partFROM "fsa-prod-cnsv".ewt76_sgnp_elg_crit-- WHERE __CDC_OPERATION = 'D'